class Solution:
    def minCost(self, houses, cost, m, n, target):
        INF = float('inf')
        # dp[c][t] = min cost, prev color c, t neighborhoods
        prev = [[INF] * (target + 1) for _ in range(n + 1)]
        # Initialize first house
        if houses[0] != 0:
            c = houses[0]
            prev[c][1] = 0
        else:
            for c in range(1, n + 1):
                prev[c][1] = cost[0][c - 1]
        for i in range(1, m):
            curr = [[INF] * (target + 1) for _ in range(n + 1)]
            colors = [houses[i]] if houses[i] != 0 else range(1, n + 1)
            for c in colors:
                paint = 0 if houses[i] != 0 else cost[i][c - 1]
                for pc in range(1, n + 1):
                    for t in range(1, target + 1):
                        if prev[pc][t] == INF:
                            continue
                        nt = t + (1 if c != pc else 0)
                        if nt <= target:
                            curr[c][nt] = min(curr[c][nt], prev[pc][t] + paint)
            prev = curr
        ans = min(prev[c][target] for c in range(1, n + 1))
        return ans if ans != INF else -1

