var minCost = function(houses, cost, m, n, target) {
    const INF = Infinity;
    let prev = Array.from({length: n+1}, () => new Array(target+1).fill(INF));
    if (houses[0] !== 0) {
        prev[houses[0]][1] = 0;
    } else {
        for (let c = 1; c <= n; c++) prev[c][1] = cost[0][c-1];
    }
    for (let i = 1; i < m; i++) {
        const curr = Array.from({length: n+1}, () => new Array(target+1).fill(INF));
        const colors = houses[i] !== 0 ? [houses[i]] : Array.from({length: n}, (_, j) => j+1);
        for (const c of colors) {
            const paint = houses[i] !== 0 ? 0 : cost[i][c-1];
            for (let pc = 1; pc <= n; pc++) {
                for (let t = 1; t <= target; t++) {
                    if (prev[pc][t] === INF) continue;
                    const nt = t + (c !== pc ? 1 : 0);
                    if (nt <= target)
                        curr[c][nt] = Math.min(curr[c][nt], prev[pc][t] + paint);
                }
            }
        }
        prev = curr;
    }
    let ans = INF;
    for (let c = 1; c <= n; c++) ans = Math.min(ans, prev[c][target]);
    return ans === INF ? -1 : ans;
};
